#!/usr/bin/env node
// gen-contract-fixtures.mjs — Emit a data-only Rust module from the real
// Groth16 fixtures so the contract test verifies ACTUAL proofs (no mock VK).
//
// Reads:
//   fixtures/verification_key.json
//   fixtures/{solvent,insolvent,boundary}/{proof,public}.json
// Writes:
//   contracts/stellaris/src/test_fixtures.rs   (@generated, data only)
//
// snarkjs Fp2 ordering is [c0, c1]; we preserve it as (x1=c0, x2=c1) to match
// the vendored groth16_verifier reference's g2_from_coords(x1,x2,y1,y2).
//
// Usage: node setup/gen-contract-fixtures.mjs

import { readFileSync, writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const FIX = join(ROOT, "fixtures");
const OUT = join(ROOT, "contracts/stellaris/src/test_fixtures.rs");

const rd = (p) => JSON.parse(readFileSync(p, "utf8"));

function g1(arr) {
  return { x: String(arr[0]), y: String(arr[1]) };
}
function g2(arr) {
  // arr = [[x_c0, x_c1], [y_c0, y_c1], [1, 0]]
  return {
    x1: String(arr[0][0]),
    x2: String(arr[0][1]),
    y1: String(arr[1][0]),
    y2: String(arr[1][1]),
  };
}

const vk = rd(join(FIX, "verification_key.json"));
const vkData = {
  alpha: g1(vk.vk_alpha_1),
  beta: g2(vk.vk_beta_2),
  gamma: g2(vk.vk_gamma_2),
  delta: g2(vk.vk_delta_2),
  ic: vk.IC.map(g1),
};

function scenario(name) {
  const proof = rd(join(FIX, name, "proof.json"));
  const signals = rd(join(FIX, name, "public.json")).map(String);
  return {
    a: g1(proof.pi_a),
    b: g2(proof.pi_b),
    c: g1(proof.pi_c),
    signals,
  };
}

const solvent = scenario("solvent");
const insolvent = scenario("insolvent");
const boundary = scenario("boundary");

const g1Lit = (g) => `G1c { x: "${g.x}", y: "${g.y}" }`;
const g2Lit = (g) =>
  `G2c { x1: "${g.x1}", x2: "${g.x2}", y1: "${g.y1}", y2: "${g.y2}" }`;
const sigLit = (s) => `[${s.map((v) => `"${v}"`).join(", ")}]`;
const icLit = (ic) => ic.map((g) => `    ${g1Lit(g)},`).join("\n");

function proofConst(name, ident, p) {
  return `/// Real Groth16 proof + public signals for the ${name} scenario.
pub const ${ident}: ProofData = ProofData {
    a: ${g1Lit(p.a)},
    b: ${g2Lit(p.b)},
    c: ${g1Lit(p.c)},
    signals: ${sigLit(p.signals)},
};`;
}

const body = `//! @generated by setup/gen-contract-fixtures.mjs — DO NOT EDIT BY HAND.
//!
//! Real Groth16 (BLS12-381) verification key, proofs, and public signals,
//! produced by the trusted setup (setup/ceremony.sh) and proof generation
//! (setup/export-fixtures.sh). These are genuine cryptographic artifacts —
//! the contract test verifies them through the real on-chain pairing check.
//!
//! Regenerate after re-running the ceremony:
//!   node setup/gen-contract-fixtures.mjs

#![cfg(test)]

/// A G1 point as decimal field-coordinate strings (affine x, y).
pub struct G1c {
    pub x: &'static str,
    pub y: &'static str,
}

/// A G2 point as decimal Fp2 coordinate strings. snarkjs Fp2 order is [c0, c1];
/// x = Fp2(x1, x2), y = Fp2(y1, y2).
pub struct G2c {
    pub x1: &'static str,
    pub x2: &'static str,
    pub y1: &'static str,
    pub y2: &'static str,
}

/// One scenario's proof (A in G1, B in G2, C in G1) and its 4 public signals
/// in circuit declaration order: [solvent, commitment, liabilities, period].
pub struct ProofData {
    pub a: G1c,
    pub b: G2c,
    pub c: G1c,
    pub signals: [&'static str; 4],
}

/// Verification key (alpha in G1; beta/gamma/delta in G2; IC = public-input
/// commitments, length = nPublicSignals + 1).
pub struct VkData {
    pub alpha: G1c,
    pub beta: G2c,
    pub gamma: G2c,
    pub delta: G2c,
    pub ic: &'static [G1c],
}

/// Real verification key exported from the Groth16 trusted setup.
pub const VK: VkData = VkData {
    alpha: ${g1Lit(vkData.alpha)},
    beta: ${g2Lit(vkData.beta)},
    gamma: ${g2Lit(vkData.gamma)},
    delta: ${g2Lit(vkData.delta)},
    ic: &[
${icLit(vkData.ic)}
    ],
};

${proofConst("solvent", "SOLVENT", solvent)}

${proofConst("insolvent", "INSOLVENT", insolvent)}

${proofConst("boundary", "BOUNDARY", boundary)}
`;

writeFileSync(OUT, body);
console.log(`[OK] wrote ${OUT}`);
console.log(`     VK.ic length: ${vkData.ic.length}`);
console.log(`     solvent signals:   ${sigLit(solvent.signals)}`);
console.log(`     insolvent signals: ${sigLit(insolvent.signals)}`);
console.log(`     boundary signals:  ${sigLit(boundary.signals)}`);
